/** UsptReprtDao.insert */
insert into uspt_reprt
	(
		reprt_id
		, last_slctn_trget_id
		, reprt_type_cd
		, reprt_sttus_cd
		, reprt_sumry_cn
		, attachment_group_id
		, makeup_req_de
		, makeup_req_cn
		, makeup_attachment_group_id
		, presentn_dt
		, sndng_mth
		, sndng_cn
		, recent_send_date
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values (
		#{reprtId}
		, #{lastSlctnTrgetId}
		, #{reprtTypeCd}
		, #{reprtSttusCd}
		, #{reprtSumryCn}
		, #{attachmentGroupId}
		, #{makeupReqDe}
		, #{makeupReqCn}
		, #{makeupAttachmentGroupId}
		, #{presentnDt}
		, #{sndngMth}
		, #{sndngCn}
		, #{recentSendDate}
		, #{creatorId}
		, #{createdDt}
		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptReprtDao.update */
update uspt_reprt
set
	reprt_sttus_cd		= #{reprtSttusCd}
	, reprt_sumry_cn	= #{reprtSumryCn}
	, makeup_req_de		= #{makeupReqDe}
	, makeup_req_cn		= #{makeupReqCn}
	, presentn_dt		= #{presentnDt}
	, sndng_mth			= #{sndngMth}
	, sndng_cn			= #{sndngCn}
	, recent_send_date	= #{recentSendDate}
	, updater_id		= #{updaterId}
	, updated_dt		= #{updatedDt}
	, attachment_group_id			= #{attachmentGroupId}
	, makeup_attachment_group_id	= #{makeupAttachmentGroupId}
where
	reprt_id = #{reprtId}

mapper.select:
/** UsptReprtDao.selectCount */
select
	count(*)
from uspt_reprt
where
	last_slctn_trget_id = #{lastSlctnTrgetId}
	and reprt_type_cd = #{reprtTypeCd}

